<?php namespace App\Services\Security; use App\Services\AuditLogService; use App\Services\Security\SecurityScanner; use Illuminate\Support\Facades\Log; class SecurityAuditService { protected $auditLogService; protected $securityScanner; public function __construct(AuditLogService $auditLogService, SecurityScanner $securityScanner) { $this->auditLogService = $auditLogService; $this->securityScanner = $securityScanner; } public function generateSecurityReport(int $userId): array { $logs = $this->auditLogService->getUserLogs($userId); $vulnerabilities = $this->securityScanner->scanUserActivity($userId); return [ 'user_id' => $userId, 'status' => $this->evaluateSecurityStatus($logs, $vulnerabilities), 'suspicious_activities' => $this->filterSuspiciousLogs($logs), 'vulnerabilities' => $vulnerabilities, 'timestamp' => now()->toDateTimeString() ]; } public function handleTwoFactorFailure(int $userId, string $ipAddress): void { $this->auditLogService->log( $userId, '2FA_FAILURE', 'فشل في المصادقة الثنائية من العنوان: ' . $ipAddress, 'critical' ); Log::warning('Security Alert: 2FA Failure for user ' . $userId . ' from ' . $ipAddress); } protected function filterSuspiciousLogs(array $logs): array { return array_filter($logs, function ($log) { return in_array($log['event'], ['LOGIN_FAILURE', '2FA_FAILURE', 'UNAUTHORIZED_ACCESS']); }); } protected function evaluateSecurityStatus(array $logs, array $vulnerabilities): string { if (count($vulnerabilities) > 0 || count($this->filterSuspiciousLogs($logs)) > 5) { return 'HIGH_RISK'; } return 'SECURE'; } }